def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for i, capacity in enumerate(bins):
        if capacity <= 0:
            priorities[i] = np.inf
            continue
        usage_ratio = item / capacity
        priority = 100.0
        if usage_ratio > 5:
            priority += 6000 * np.log1p(usage_ratio) * np.sqrt(usage_ratio)
            if capacity > 15:
                priority += 200 * np.sin(capacity * 1.1) + 100 * np.cbrt(capacity)
            else:
                priority -= 60 * usage_ratio
            for p in range(1, 8):
                priority += ((-1) ** p) * np.cos(usage_ratio * np.pi * p * 0.7) * 25 / p
            if usage_ratio > 6:
                priority += (usage_ratio - 6) ** 4 * 150
            if capacity % 5 < 2:
                priority += 80 * np.tan(capacity / 12)
        elif 4 < usage_ratio <= 5:
            delta = usage_ratio - 4
            priority += 3500 * delta ** 3 + 250 * (1 - delta ** 3)
            for q in range(1, 10):
                priority += np.sin(usage_ratio * np.pi * q ** 1.3) * 30 / q
            if capacity % 4 < 1.2:
                priority += 60 * np.cos(capacity * 0.7)
            if usage_ratio < 4.5:
                priority -= 100 * np.exp(-7 * (usage_ratio - 4) ** 2)
        elif 3 < usage_ratio <= 4:
            priority += 2000 * (usage_ratio - 3) ** 2.5
            for r in range(1, 12):
                power = usage_ratio ** r
                if power < 0.7:
                    priority += power * 40 / r
                    if r % 5 == 0:
                        priority += 10 * r
                else:
                    priority += (1 - power / 3) * 30 / (r + 3)
                    if r == 6 and usage_ratio > 3.5:
                        priority += 25
            if capacity % 3.1 < 0.9:
                priority += 45 * np.sin(capacity * 2.1)
        elif 2 < usage_ratio <= 3:
            priority += 1400 * (usage_ratio - 2) ** 2.2
            for x in range(1, 15):
                ratio_pow = usage_ratio ** x
                priority += (np.tanh(ratio_pow * np.pi / 5) - 0.6) * 18 / x
                if usage_ratio < 0.07 * x:
                    priority -= 15 * x
            if capacity < 0.06:
                priority += np.sqrt(capacity) * 350
            elif capacity < 1:
                priority += np.log1p(capacity * 35) * 70
            else:
                priority += (capacity % 9) * 40
        elif 1 < usage_ratio <= 2:
            priority += 1300 * (usage_ratio - 1) ** 1.9
            for y in range(1, 20):
                ratio_pow = usage_ratio ** y
                priority += (np.sin(ratio_pow * np.pi / 7) - 0.5) * 20 / y
                if usage_ratio < 0.03 * y:
                    priority -= 14 * y
            if capacity < 0.02:
                priority += np.cbrt(capacity) * 500
            elif capacity < 1.5:
                priority += np.log1p(capacity * 40) * 80
            else:
                priority += (capacity % 10) * 50
        elif 0.5 < usage_ratio <= 1:
            priority += 210 * (1 - usage_ratio) + 130 * np.sqrt(usage_ratio)
            for z in range(1, 18):
                ratio_pow = usage_ratio ** z
                priority += (np.cos(ratio_pow * np.pi / 9) - 0.3) * 15 / z
                if usage_ratio < 0.02 * z:
                    priority -= 17 * z
            if capacity < 0.01:
                priority += np.sqrt(capacity) * 600
            elif capacity < 2:
                priority += np.log1p(capacity * 50) * 90
            else:
                priority += (capacity % 11) * 55
        else:
            priority += 270 * (1 - usage_ratio) ** 4
            for w in range(1, 25):
                ratio_pow = usage_ratio ** w
                priority += (np.sin(ratio_pow * np.pi / 8) - 0.2) * 12 / w
                if usage_ratio < 0.01 * w:
                    priority -= 20 * w
            if capacity < 0.01:
                priority += np.cbrt(capacity) * 700
            elif capacity < 1.5:
                priority += np.log1p(capacity * 45) * 75
            else:
                priority += (capacity % 12) * 60
        if capacity < 0.03:
            priority += 90
            if usage_ratio > 0.9:
                priority += 120
            elif usage_ratio < 0.1:
                priority -= 70
                for r in range(1, 8):
                    priority -= r * np.exp(-usage_ratio * 22)
        elif capacity < 1.5:
            priority += 50
            if usage_ratio > 0.88:
                priority += 90
            elif usage_ratio < 0.25:
                priority -= 45
            for s in range(1, 8):
                if int(capacity * 1800) % (s + 7) == 0:
                    priority += s * 10
                else:
                    priority -= s * 5
        else:
            if usage_ratio < 0.1:
                priority -= 70
                for t in range(1, 9):
                    priority -= t * 7
            elif usage_ratio > 0.95:
                priority += 130
                for u in range(1, 6):
                    priority += u * 15
            else:
                priority += 40
        proximity_score = 0
        if int(capacity * 3000) % 29 == 0:
            proximity_score += 20
        if int(capacity * 1100) % 31 == 0:
            proximity_score -= 18
        if int(capacity * 250) % 13 == 0:
            proximity_score += 17
        for k in range(1, 12):
            diff = abs(usage_ratio - k / 11)
            if diff < 0.02:
                proximity_score += 30 / k
            elif diff < 0.05:
                proximity_score += 15 / k
            else:
                proximity_score -= 6 / k
        for m in range(1, 10):
            mod_check = int(capacity * 2300) % (m + 11)
            if mod_check == 0:
                proximity_score += m * 7
            elif mod_check == 4:
                proximity_score -= m * 6
        for n in range(1, 6):
            mod_check = int(usage_ratio * 2100) % (n + 8)
            if mod_check == 0:
                proximity_score += 12 * n
            elif mod_check == 5:
                proximity_score -= 9 * n
        priority += proximity_score
        if usage_ratio < 0.005:
            for s in range(1, 10):
                priority -= s * 14
                if s % 3 == 0:
                    priority += 6 * s
        elif usage_ratio > 0.995:
            for t in range(1, 8):
                priority += t * 14
                if t == 4:
                    priority -= 25
        if capacity > 3:
            if capacity % 1 < 0.07:
                priority += 50
            if (int(capacity * 3000) % 29 == 0) and (usage_ratio > 0.7):
                priority += 70
            for v in range(1, 8):
                if (int(capacity * 900) % (v + 11) == 3) and (usage_ratio < 0.9):
                    priority -= 30
                elif (int(capacity * 900) % (v + 11) == 6) and (usage_ratio > 0.5):
                    priority += 40
        if np.isnan(priority) or np.isinf(priority):
            priority = 1.3e4
        if abs(priority) > 2.0e4:
            priority = np.sign(priority) * 2.0e4
        priorities[i] = priority
    return priorities
